#include <stdlib.h>
#include <string.h>

char *make_copy(const char *src, size_t n) {
	char *buf = malloc(n + 1);
	memcpy(buf, src, n);
	buf[n] = '\0';
	return buf;
}

#include <stdlib.h>
#include <string.h>

char *make_copy(const char *src, size_t n) {
	char *buf = malloc(n + 1);
	if (buf == NULL) {
		return NULL;
	}
	memcpy(buf, src, n);
	buf[n] = '\0';
	return buf;
}
